import logging
import os
import json
from azure.identity import ManagedIdentityCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, EventGridEvent
from azure.functions import BlobTrigger

# Environment variables
BLOB_CONNECTION_STRING = os.getenv("BLOB_CONNECTION_STRING")
COSMOS_DB_URL = os.getenv("COSMOS_DB_URL")
COSMOS_DB_KEY = os.getenv("COSMOS_DB_KEY")
COSMOS_DB_DATABASE = os.getenv("COSMOS_DB_DATABASE")
COSMOS_DB_CONTAINER = os.getenv("COSMOS_DB_CONTAINER")
EVENT_GRID_TOPIC_ENDPOINT = os.getenv("EVENT_GRID_TOPIC_ENDPOINT")

# Managed Identity Credential
credential = ManagedIdentityCredential()

# Blob Service Client
blob_service_client = BlobServiceClient.from_connection_string(BLOB_CONNECTION_STRING)

# Cosmos DB Client
cosmos_client = CosmosClient(COSMOS_DB_URL, credential=credential)
database = cosmos_client.get_database_client(COSMOS_DB_DATABASE)
container = database.get_container_client(COSMOS_DB_CONTAINER)

# Event Grid Client
event_grid_client = EventGridPublisherClient(EVENT_GRID_TOPIC_ENDPOINT, credential)

def main(blob: BlobTrigger):
    try:
        # Validate blob input
        if not blob.name.endswith('.json'):
            logging.error("Unsupported file type.")
            return

        # Read blob content
        blob_client = blob_service_client.get_blob_client(container=blob.container, blob=blob.name)
        blob_data = blob_client.download_blob().readall()
        data = json.loads(blob_data)

        # Validate data structure
        if 'id' not in data or 'value' not in data:
            logging.error("Invalid data structure.")
            return

        # Write to Cosmos DB
        container.upsert_item(data)

        # Send notification via Event Grid
        event = EventGridEvent(
            subject="NewFileProcessed",
            event_type="FileProcessed",
            data={"fileName": blob.name, "status": "Processed"},
            data_version="1.0"
        )
        event_grid_client.send([event])

        logging.info(f"Processed blob: {blob.name}")

    except Exception as e:
        logging.error(f"Error processing blob: {e}")